#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

int n,m,dfn[N],dep[N],num,f[N][17],sz[N],c[N];
vector<int> g[N];

void dfs(int x,int fa){
    dep[x]=dep[fa]+1,dfn[x]=++num,sz[x]=1;
    for(int y:g[x])
        if(y!=fa){
            f[y][0]=x;
            for(int i=1;(1<<i)<=dep[x];i++)
                f[y][i]=f[f[y][i-1]][i-1];
            dfs(y,x);
            sz[x]+=sz[y];
        }
}

int LCA(int x,int y){
    if(dep[x]<dep[y])
        swap(x,y);
    for(int i=16;i>=0;i--)
        if(dep[f[x][i]]>=dep[y])
            x=f[x][i];
    if(x==y)
        return x;
    for(int i=16;i>=0;i--)
        if(f[x][i]!=f[y][i])
            x=f[x][i],y=f[y][i];
    return f[x][0];
}

void add(int x,int k){
    for(;x<=n;x+=(x&(-x)))
        c[x]+=k;
}

int ask(int x){
    int res=0;
    for(;x;x-=(x&(-x)))
        res+=c[x];
    return res;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1,u,v;i<n;i++){
        scanf("%d%d",&u,&v);
        g[u].push_back(v);
        g[v].push_back(u);
    }
    dfs(1,0);
    while(m--){
        char op[2];
        int u,v;
        scanf("%s",op);
        scanf("%d%d",&u,&v);
        if(op[0]=='P')
            add(dfn[u],1),add(dfn[v],1),add(dfn[LCA(u,v)],-2);
        else{
            if(dep[u]<dep[v])
                swap(u,v);
            printf("%d\n",ask(dfn[u]+sz[u]-1)-ask(dfn[u]-1));
        }
    }
    return 0;
}
